def sanitize_user_id(raw_user_id):
    """
    Validate and sanitize user ID.
    Only allow alphanumeric characters and hyphens, with length limits.
    Returns sanitized user_id or 'anonymous'.
    """
    if not raw_user_id:
        return "anonymous"

    # Strip and enforce length limit
    raw_user_id = str(raw_user_id).strip()[:64]

    # Allowlist: only alphanumeric, hyphens, underscores
    if not re.match(r'^[a-zA-Z0-9_-]+$', raw_user_id):
        logger.warning("Invalid user_id format rejected")
        return "invalid"

    return raw_user_id


def sanitize_session_id(raw_session_id):
    """
    Validate and sanitize session ID.
    Hash the session ID to prevent sensitive data leakage in metrics.
    """
    if not raw_session_id:
        return "no_session"

    raw_session_id = str(raw_session_id).strip()[:128]

    # Allowlist: only alphanumeric, hyphens, underscores
    if not re.match(r'^[a-zA-Z0-9_-]+$', raw_session_id):
        logger.warning("Invalid session_id format rejected")
        return "invalid_session"

    # SECURITY: Hash session IDs to avoid exposing actual session tokens in metrics
    # This prevents session hijacking via metrics endpoint
    hashed = hashlib.sha256(raw_session_id.encode('utf-8')).hexdigest()[:16]
    return f"sess_{hashed}"


def normalize_path(raw_path):
    """
    Normalize and validate request path against allowlist.
    Replaces dynamic path segments with placeholders to limit cardinality.
    Rejects paths not matching any known pattern.
    """
    if not raw_path:
        return "unknown"

    # Remove query string and fragment
    path = raw_path.split('?')[0].split('#')[0]

    # Normalize: lowercase, strip trailing slashes (except root)
    path = path.lower().rstrip('/') or '/'

    # Remove any path traversal attempts
    path = re.sub(r'\.\.', '', path)
    path = re.sub(r'/+', '/', path)

    # Enforce length limit
    if len(path) > 256:
        logger.warning("Path too long, rejecting")
        return "path_too_long"

    # Check against allowlist
