def sanitize_method(method):
    """Validate HTTP method against allowlist."""
    allowed_methods = {'GET', 'POST', 'PUT', 'DELETE', 'PATCH', 'HEAD', 'OPTIONS'}
    method = str(method).upper().strip()
    if method in allowed_methods:
        return method
    return "UNKNOWN"


def sanitize_status_code(status_code):
    """Validate and bucket status codes."""
    try:
        code = int(status_code)
        if 100 <= code <= 599:
            return str(code)
    except (ValueError, TypeError):
        pass
    return "unknown"


